#!/bin/bash
# ==============================================================================
# TDZ NETWORK CONTROL
# x-credit: https://info.tuhinbro.website
# TG: @TuhinBroh
# ==============================================================================

VERSION="0.0.8 BETA"

CORE_FILE="/usr/local/bin/.tdz_network_core"

echo "" | base64 -d | tr -d '\r' > /tmp/.core_temp.sh
chmod +x /tmp/.core_temp.sh

cat /tmp/.core_temp.sh > "$CORE_FILE"
rm -f /tmp/.core_temp.sh
chmod +x "$CORE_FILE"

if [[ "$(realpath "$0")" != "$CORE_FILE" ]]; then
    bash "$CORE_FILE" "$@"
    rm -f "$0"
    exit 0
fi
exec bash "$CORE_FILE" "$@"
